<?php
namespace App\Domain\Hunts;
use App\Domain\Combat\CombatActionType;use App\Domain\Hunts\Playback\HuntingPlaybackResult;use App\Models\Hunt;use App\Models\HuntCombatEvent;use InvalidArgumentException;
class HuntCombatEventPersister{
 public function persist(Hunt $hunt,HuntingPlaybackResult $playback,array $participantIdentifiers){$rows=[];$sequence=1;$health=[];$now=now();foreach($playback->events() as $timed){$action=$timed['action'];$actor=$action->attackerIdentifier();$target=$action->defenderIdentifier();if(!isset($participantIdentifiers[$actor])||!isset($participantIdentifiers[$target]))throw new InvalidArgumentException('Combat event participant missing.');$before=(int)$action->defenderHealthBefore();$after=(int)$action->defenderHealthAfter();$damage=(int)$action->damage();if(isset($health[$target])&&$health[$target]!==$before)throw new InvalidArgumentException('Combat event health chain mismatch.');if(!$action->hit()&&($damage!==0||$action->critical()||$before!==$after))throw new InvalidArgumentException('Invalid missed attack event.');if($action->critical()&&!$action->hit())throw new InvalidArgumentException('Critical event must hit.');if($after>$before||$after!==max(0,$before-$damage))throw new InvalidArgumentException('Invalid attack damage event.');$rows[]=['hunt_id'=>$hunt->id,'sequence'=>$sequence++,'round'=>(int)$action->roundNumber(),'actor_identifier'=>$actor,'target_identifier'=>$target,'event_type'=>CombatActionType::BASIC_ATTACK,'did_hit'=>(bool)$action->hit(),'hit_probability'=>(int)round($action->hitChance()*100),'hit_roll'=>(int)round($action->randomRoll()*100),'critical_probability'=>$action->hit()?(int)round($action->criticalChance()*100):null,'critical_roll'=>$action->criticalRoll()===null?null:(int)round($action->criticalRoll()*100),'is_critical'=>(bool)$action->critical(),'damage'=>$damage,'healing'=>0,'target_health_before'=>$before,'target_health_after'=>$after,'playback_offset_ms'=>$timed['playback_offset_ms'],'playback_duration_ms'=>$timed['playback_duration_ms'],'created_at'=>$now,'updated_at'=>$now];$health[$target]=$after;}if(!$rows)throw new InvalidArgumentException('New Hunt requires combat events.');HuntCombatEvent::insert($rows);if(HuntCombatEvent::where('hunt_id',$hunt->id)->count()!==count($rows))throw new InvalidArgumentException('Combat event persistence failed.');}
}
